// What you write (JSX):
const el = <h1 className="title">Hello</h1>;

// What Babel produces before the browser runs it:
const el = React.createElement('h1', { className: 'title' }, 'Hello');

// Before (CDN — global React)
function App() {
  const [count, setCount] = React.useState(0);
  return <button onClick={() => setCount(c => c + 1)}>{count}</button>;
}

// After (Vite — named import)
import { useState } from 'react';

export default function App() {
  const [count, setCount] = useState(0);
  return <button onClick={() => setCount(c => c + 1)}>{count}</button>;
}

// React 17 and earlier (still works but deprecated in 18)
ReactDOM.render(<App />, document.getElementById('root'));

// React 18+ (concurrent features enabled)
const root = ReactDOM.createRoot(document.getElementById('root'));
root.render(<App />);

// Updating the root later (e.g. after a data change)
root.render(<App newProp={value} />);
